### Example: tree-custom
```html
<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>Tree custom example</title>
    <script type="module">
      import { addIcons } from '@siemens/ix-icons';
      import { iconStar, iconCut, iconPrint } from '@siemens/ix-icons/icons';

      addIcons({ iconStar, iconCut, iconPrint });
    </script>
  </head>
  <body>
    <div style="height: 8rem; width: 100%">
      <ix-button variant="tertiary" id="expand" style="margin-bottom: 2rem">Expand Tree</ix-button
      >
      <ix-tree root="root" id="tree"></ix-tree>
    </div>

    <script>
      (async function () {
        await window.customElements.whenDefined('ix-tree');
        const tree = document.getElementById('tree');

        const expandButton = document.getElementById('expand');
        expandButton.addEventListener('click', () => {
          tree.context = {
            sample: {
              isExpanded: true,
              isSelected: false,
            },
            'sample-child-2': {
              isSelected: true,
              isExpanded: false,
            },
          };
        });

        tree.renderItem = (index, item, dataList, context, update) => {
          const el = document.createElement('ix-tree-item');
          el.hasChildren = item.hasChildren;
          el.context = context[item.id];

          const div = document.createElement('div');
          div.style.display = 'flex';

          const name = document.createElement('span');
          const icon = document.createElement('ix-icon');
          icon.name = item.data.icon;
          icon.style.marginRight = '0.5rem';

          div.appendChild(icon);
          div.appendChild(name);

          name.innerText = item.data.name;

          el.appendChild(div);

          update((updateTreeItem) => {
            name.innerText = updateTreeItem.data.name;
          });

          return el;
        };

        tree.model = {
          root: {
            id: 'root',
            data: null,
            hasChildren: true,
            children: ['sample'],
          },
          sample: {
            id: 'sample',
            data: {
              name: 'Sample',
              icon: 'star',
            },
            hasChildren: true,
            children: ['sample-child-1', 'sample-child-2'],
          },
          'sample-child-1': {
            id: 'sample-child-1',
            data: {
              name: 'Sample Child 1',
              icon: 'cut',
            },
            hasChildren: false,
            children: [],
          },
          'sample-child-2': {
            id: 'sample-child-2',
            data: {
              name: 'Sample Child 2',
              icon: 'print',
            },
            hasChildren: false,
            children: [],
          },
        };
      })();
    </script>
    <script type="module" src="./init.js"></script>
  </body>
</html>
```

