}

/* Support high-resolution displays */
@media (-webkit-min-device-pixel-ratio: 2), (min-resolution: 192dpi) {
    .icon {
        /* Use SVG or high-resolution images */
        background-image: url('icon@2x.png');
        background-size: contain;
    }
}
